mapper.select:
select id, visit_type, visitor_name, visitor_phone, elder_name, appointment_time, case when status = 0 and appointment_time < now() then 3 else status end as status, arrival_time, create_by, create_time, update_by, update_time, remark from visitor_appointment
and visitor_name like concat('%', #{visitorName}, '%')
and visitor_phone like concat('%', #{visitorPhone}, '%')
and visit_type = #{visitType}
and status = 0 and appointment_time < now() and status = 0 and appointment_time >= now() and status = #{status}
and appointment_time >= #{params.beginTime}
and appointment_time <= concat(#{params.endTime}, ' 23:59:59')
order by appointment_time desc
